#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 100005;
int n, p[N], fa[N], S, T;
struct ed {
	int to, Next;
};
ed e[N << 1];
int cnt, Head[N];
double dp[N][2];
void link (int u, int v) {
	e[++cnt] = (ed) {v, Head[u]};
	Head[u] = cnt;
	return;
}
int find (int x) {
	if (fa[x] == x) {
		return x;
	}
	return fa[x] = find (fa[x]);
}
void dfs (int u, int fa) {
	dp[u][1] = p[u];
	dp[u][0] = 0;
	for (int i = Head[u]; i; i = e[i].Next) {
		int v = e[i].to;
		if (v == fa) {
			continue;
		}
		dfs (v, u);
		dp[u][0] += max (dp[v][0], dp[v][1]);
		dp[u][1] += dp[v][0];
	}
	return;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> p[i];
		fa[i] = i;
	}
	for (int i = 1; i <= n; i++) {
		int u, v;
		cin >> u;
		u++;
		cin >> v;
		v++;
		if (find (u) == find (v)) {
			S = u;
			T = v;
			continue;
		}
		link (u, v);
		link (v, u);
		fa[find (v)] = find (u);
	}
	double k, ans = 0;
	cin >> k;
	dfs (S, 0);
	ans = dp[S][0];
	dfs (T, 0);
	ans = max (ans, dp[T][0]);
	cout << fixed << setprecision (1) << ans * k;
	return 0;
}
